  ('76b5d47a-0e36-45f6-b033-0b47e74f19fc'::uuid, '012d52b9-17f0-43d3-a7af-b4cce04f55a2'::uuid, null, 'product_updated', 'manufacturer_scraper_auto_review', '{"id":"012d52b9-17f0-43d3-a7af-b4cce04f55a2","title":"DHC Platinum Nanocolloid 30-Day Supply","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"17f6ebfb-bc28-4471-84e6-12fccfd93e06","category":null,"currency":"THB","platform":"manual","title_en":"DHC Platinum Nanocolloid 30-Day Supply","title_th":"ดีเอชซี แพลตตินัม นาโนคอลลอยด์ 30 วัน","image_url":"https://www.dhc.co.jp/dw/image/v2/BLLL_PRD/on/demandware.static/-/Sites-dhc_catalog-ms/default/dw4fa2b91f/large/2379/2379_G.png?sw=256&sh=256&sm=cut","brand_name":"dhc","created_at":"2026-05-21T10:14:08.83192+00:00","source_url":"https://www.dhc.co.jp/goods/2379.html","updated_at":"2026-05-21T10:14:08.854466+00:00","admin_notes":null,"description":"プラチナはサビない！ 体の中へも、プラチナパワー","product_url":"https://www.dhc.co.jp/goods/2379.html","label_status":"missing","price_amount":null,"product_kind":"supplement","description_en":"Platinum nanocolloid supplement with 5 mcg platinum per capsule.","description_th":"อาหารเสริมแพลตตินัม นาโนคอลลอยด์ 5 ไมโครกรัมต่อแคปซูล","normalized_url":"https://www.dhc.co.jp/goods/2379.html","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"locale":"ja","parser":"dhc_demandware_health_supplements_v1","titleEn":"DHC Platinum Nanocolloid 30-Day Supply","titleTh":"ดีเอชซี แพลตตินัม นาโนคอลลอยด์ 30 วัน","htmlHash":"988e29178a45c36b864e11f13cfb7c67c979ab14ac4e0e2b78b8adae630e5c6f","nutrition":"「サビない」貴金属として知られ、食品への配合が厚生労働省から認められている白金（はっきん）=プラチナ。これを2ナノサイズ（10億分の2メートル）まで超微粒子化した白金ナノコロイドを、1日摂取目安量あたり5μgも配合しました。 イキイキと若々しく毎日をすごしたい方、いつもキレイでいたい方の健康・美容ケアにおすすめです。 「ナノコロイド」とは？ 「ナノ」とは、大きさや長さの単位で「10億分の1メートル」のこと。「コロイド」とは、水の中に物質が溶けるのではなく、細かい物質が分散し溶けているように見える状態のことをさします。仮に地球を1ナノに縮小すると、ピンポン玉ほどのサイズになります。 金属を身体に入れても大丈夫？ 白金は「食品の酸化を防ぐ食品添加物」として、厚生労働省から安全性を認められている数少ない金属のひとつです。口にいれても問題なく、安心してお摂りいただけます。 安全とはいえ、やはり体内に蓄